const BADGE_DATA_URL = "data:image/png;base64,"

/**
 * WranglBadge — the in-app logo mark.
 *
 * The official Berkely Distribution logo badge is embedded inline as a
 * base64-encoded PNG. No separate asset file needed; no network request.
 * Used in the desktop sidebar header and mobile top bar.
 *
 * The PNG is 192x192 — sharp on retina displays at sidebar size (40px → 80px)
 * and still acceptable on the rare 4x display. If you ever need a sharper
 * version for very large UI (login screen 100px+), swap to a 384px PNG.
 *
 * Props:
 *   size — pixel dimension (square). Default 40.
 *   className — optional Tailwind classes for sizing/positioning.
 */
export default function WranglBadge({ size = 40, className = "" }) {
  return (
    <img
      src={BADGE_DATA_URL}
      alt="Wrangl"
      width={size}
      height={size}
      className={className}
      style={{
        display: "block",
        flexShrink: 0,
      }}
    />
  )
}
